import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    red: '#f43f5e',
    positive: '#10b981',
    negative: '#f43f5e',
  },
  font: "'JetBrains Mono', monospace",
};

const ROWS = 3, COLS = 4;
const WALL = { r: 1, c: 1 };
const GOAL = { r: 0, c: 3 };
const PIT = { r: 1, c: 3 };
const STEP_COST = -0.04;

const ACTIONS = [
  { name: 'Up', dr: -1, dc: 0 },
  { name: 'Right', dr: 0, dc: 1 },
  { name: 'Down', dr: 1, dc: 0 },
  { name: 'Left', dr: 0, dc: -1 },
];

const ARROW_PATHS = [
  'M0,-7 L4,1 L-4,1Z',
  'M7,0 L-1,4 L-1,-4Z',
  'M0,7 L4,-1 L-4,-1Z',
  'M-7,0 L1,4 L1,-4Z',
];

function isWall(r, c) { return r === WALL.r && c === WALL.c; }
function isGoal(r, c) { return r === GOAL.r && c === GOAL.c; }
function isPit(r, c) { return r === PIT.r && c === PIT.c; }
function isTerminal(r, c) { return isGoal(r, c) || isPit(r, c); }

function nextState(r, c, action) {
  let nr = r + action.dr, nc = c + action.dc;
  if (nr < 0 || nr >= ROWS || nc < 0 || nc >= COLS || isWall(nr, nc)) { nr = r; nc = c; }
  return { r: nr, c: nc };
}

function getReward(nr, nc) {
  if (isGoal(nr, nc)) return 1.0;
  if (isPit(nr, nc)) return -1.0;
  return STEP_COST;
}

function bellmanUpdate(V, gamma) {
  const nV = V.map(row => [...row]);
  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      if (isTerminal(r, c) || isWall(r, c)) continue;
      let best = -Infinity;
      for (const a of ACTIONS) {
        const ns = nextState(r, c, a);
        const val = getReward(ns.r, ns.c) + gamma * (isTerminal(ns.r, ns.c) ? 0 : V[ns.r][ns.c]);
        if (val > best) best = val;
      }
      nV[r][c] = best;
    }
  }
  return nV;
}

function getBestAction(V, r, c, gamma) {
  if (isTerminal(r, c) || isWall(r, c)) return -1;
  let best = -Infinity, idx = 0;
  ACTIONS.forEach((a, i) => {
    const ns = nextState(r, c, a);
    const val = getReward(ns.r, ns.c) + gamma * (isTerminal(ns.r, ns.c) ? 0 : V[ns.r][ns.c]);
    if (val > best) { best = val; idx = i; }
  });
  return idx;
}

function getActionValues(V, r, c, gamma) {
  return ACTIONS.map((a, i) => {
    const ns = nextState(r, c, a);
    const reward = getReward(ns.r, ns.c);
    const done = isTerminal(ns.r, ns.c);
    const futureV = done ? 0 : V[ns.r][ns.c];
    return { name: a.name, value: reward + gamma * futureV, reward, futureV, done, idx: i };
  });
}

function initV() { return Array.from({ length: ROWS }, () => Array(COLS).fill(0)); }

function valColor(v, forBg) {
  if (v > 0.01) {
    const t = Math.min(v / 1.0, 1);
    return forBg ? `rgba(16,185,129,${t * 0.45})` : theme.colors.positive;
  } else if (v < -0.01) {
    const t = Math.min(-v / 1.0, 1);
    return forBg ? `rgba(244,63,94,${t * 0.45})` : theme.colors.negative;
  }
  return forBg ? 'rgba(255,255,255,0.03)' : theme.colors.textMuted;
}

export default function App() {
  const [V, setV] = useState(initV);
  const [gamma, setGamma] = useState(0.9);
  const [iter, setIter] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [hovered, setHovered] = useState(null);
  const playRef = useRef(false);
  const gammaRef = useRef(gamma);
  gammaRef.current = gamma;

  const step = () => {
    setV(prev => bellmanUpdate(prev, gammaRef.current));
    setIter(prev => prev + 1);
  };

  const reset = () => {
    setPlaying(false); playRef.current = false;
    setV(initV()); setIter(0);
  };

  useEffect(() => {
    playRef.current = playing;
    if (!playing) return;
    const id = setInterval(() => {
      if (!playRef.current) { clearInterval(id); return; }
      setV(prev => {
        const nv = bellmanUpdate(prev, gammaRef.current);
        let maxD = 0;
        for (let r = 0; r < ROWS; r++)
          for (let c = 0; c < COLS; c++)
            maxD = Math.max(maxD, Math.abs(nv[r][c] - prev[r][c]));
        if (maxD < 0.0005) { setPlaying(false); playRef.current = false; }
        return nv;
      });
      setIter(prev => prev + 1);
    }, 700);
    return () => clearInterval(id);
  }, [playing]);

  const handleGamma = (val) => {
    setGamma(val); setV(initV()); setIter(0);
    setPlaying(false); playRef.current = false;
  };

  const hoverInfo = useMemo(() => {
    if (!hovered || isWall(hovered.r, hovered.c) || isTerminal(hovered.r, hovered.c)) return null;
    return getActionValues(V, hovered.r, hovered.c, gamma);
  }, [hovered, V, gamma]);

  const CW = 125, CH = 82, PAD = 4;
  const svgW = COLS * CW + PAD * 2, svgH = ROWS * CH + PAD * 2;

  const converged = iter > 0 && (() => {
    const nv = bellmanUpdate(V, gamma);
    let d = 0;
    for (let r = 0; r < ROWS; r++) for (let c = 0; c < COLS; c++) d = Math.max(d, Math.abs(nv[r][c] - V[r][c]));
    return d < 0.001;
  })();

  const getInsight = () => {
    if (iter === 0) return 'All values start at 0. Click Step to run one Bellman update -- watch values appear near the goal first!';
    if (iter === 1) return 'The goal neighbor found reward! V = R + gamma*0 = 1.0. Values propagate one step per iteration.';
    if (iter <= 3) return 'The wave spreads! Each cell picks its BEST action: V(s) = max over actions of [R + gamma * V(next)]. Hover a cell to see the math.';
    if (converged) return 'Converged! Arrows show the optimal policy. Notice cells near the trap go AROUND it. Try changing gamma to see how planning horizon affects the path.';
    return 'Values still propagating. Cells far from the goal take more iterations. The step cost (-0.04) penalizes longer paths.';
  };

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', fontFamily: theme.font, display: 'flex', justifyContent: 'center', padding: '16px 12px' }}>
      <div style={{ maxWidth: 580, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700, color: theme.colors.text }}>Bellman Value Iteration</div>
            <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginTop: 2 }}>Robot finds the optimal path to treasure</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={step} disabled={playing || converged} style={{ background: theme.colors.primary, color: '#fff', border: 'none', borderRadius: 6, padding: '5px 12px', fontSize: 12, fontFamily: theme.font, cursor: playing || converged ? 'default' : 'pointer', opacity: playing || converged ? 0.4 : 1 }}>Step</button>
            <button onClick={() => { if (playing) { setPlaying(false); playRef.current = false; } else { setPlaying(true); } }} disabled={converged} style={{ background: playing ? theme.colors.orange : theme.colors.surface, color: playing ? '#000' : theme.colors.text, border: `1px solid ${playing ? theme.colors.orange : theme.colors.border}`, borderRadius: 6, padding: '5px 12px', fontSize: 12, fontFamily: theme.font, cursor: converged ? 'default' : 'pointer', opacity: converged ? 0.4 : 1 }}>{playing ? 'Pause' : 'Play'}</button>
            <button onClick={reset} style={{ background: theme.colors.surface, color: theme.colors.textSecondary, border: `1px solid ${theme.colors.border}`, borderRadius: 6, padding: '5px 10px', fontSize: 12, fontFamily: theme.font, cursor: 'pointer' }}>Reset</button>
          </div>
        </div>

        {/* Grid */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '12px 8px', border: `1px solid ${theme.colors.border}` }}>
          <svg width="100%" viewBox={`0 0 ${svgW} ${svgH}`} style={{ display: 'block' }}>
            {Array.from({ length: ROWS }, (_, r) =>
              Array.from({ length: COLS }, (_, c) => {
                const x = PAD + c * CW, y = PAD + r * CH;
                const isW = isWall(r, c), isG = isGoal(r, c), isP = isPit(r, c), isT = isTerminal(r, c);
                const val = V[r][c];
                const isHov = hovered && hovered.r === r && hovered.c === c;
                const bestA = (!isW && !isT && iter > 0) ? getBestAction(V, r, c, gamma) : -1;
                const showArrow = bestA >= 0 && Math.abs(val) > 0.001;

                let bg = valColor(val, true);
                if (isW) bg = 'rgba(255,255,255,0.04)';
                if (isG) bg = 'rgba(16,185,129,0.3)';
                if (isP) bg = 'rgba(244,63,94,0.3)';

                return (
                  <g key={`${r}-${c}`}
                    onMouseEnter={() => setHovered({ r, c })}
                    onMouseLeave={() => setHovered(null)}
                    style={{ cursor: (!isW && !isT) ? 'pointer' : 'default' }}>
                    <rect x={x + 2} y={y + 2} width={CW - 4} height={CH - 4} rx={8}
                      fill={bg}
                      stroke={isHov ? theme.colors.primary : theme.colors.border}
                      strokeWidth={isHov ? 2 : 1}
                      style={{ transition: 'fill 0.4s ease, stroke 0.2s ease' }} />
                    {isW && (
                      <g>
                        {[0, 1, 2, 3, 4].map(i => (
                          <line key={i} x1={x + 15 + i * 20} y1={y + CH - 8} x2={x + 25 + i * 20} y2={y + 8}
                            stroke={theme.colors.textMuted} strokeWidth={1} opacity={0.3} />
                        ))}
                        <text x={x + CW / 2} y={y + CH / 2 + 4} textAnchor="middle" fontSize={12} fill={theme.colors.textMuted} fontFamily={theme.font}>Wall</text>
                      </g>
                    )}
                    {isG && (
                      <g>
                        <text x={x + CW / 2} y={y + CH / 2 - 8} textAnchor="middle" fontSize={20}>+</text>
                        <text x={x + CW / 2} y={y + CH / 2 + 6} textAnchor="middle" fontSize={14} fontWeight={700} fill={theme.colors.positive} fontFamily={theme.font}>+1</text>
                        <text x={x + CW / 2} y={y + CH / 2 + 20} textAnchor="middle" fontSize={9} fill={theme.colors.textSecondary} fontFamily={theme.font}>GOAL</text>
                      </g>
                    )}
                    {isP && (
                      <g>
                        <text x={x + CW / 2} y={y + CH / 2 + 6} textAnchor="middle" fontSize={14} fontWeight={700} fill={theme.colors.negative} fontFamily={theme.font}>-1</text>
                        <text x={x + CW / 2} y={y + CH / 2 + 20} textAnchor="middle" fontSize={9} fill={theme.colors.textSecondary} fontFamily={theme.font}>TRAP</text>
                      </g>
                    )}
                    {!isW && !isT && (
                      <g>
                        <text x={x + CW / 2} y={y + CH / 2 + (showArrow ? -6 : 4)} textAnchor="middle"
                          fontSize={iter === 0 ? 11 : 14} fontWeight={600}
                          fill={iter === 0 ? theme.colors.textMuted : valColor(val, false)}
                          fontFamily={theme.font}
                          style={{ transition: 'fill 0.3s ease' }}>
                          {iter === 0 ? '0.00' : val.toFixed(2)}
                        </text>
                        {showArrow && (
                          <path d={ARROW_PATHS[bestA]}
                            transform={`translate(${x + CW / 2},${y + CH / 2 + 14})`}
                            fill={theme.colors.yellow} opacity={0.85}
                            style={{ transition: 'all 0.3s ease' }} />
                        )}
                      </g>
                    )}
                  </g>
                );
              })
            )}
          </svg>

          {/* Hover Detail Panel */}
          <div style={{ minHeight: 52, marginTop: 8, padding: '6px 10px', background: theme.colors.surfaceAlt, borderRadius: 8, transition: 'all 0.2s ease' }}>
            {hoverInfo ? (
              <div>
                <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginBottom: 4 }}>
                  Bellman update for cell ({hovered.r},{hovered.c}): V(s) = max action of [ R + {gamma} * V(next) ]
                </div>
                <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                  {hoverInfo.map((av, i) => {
                    const isBest = iter > 0 && i === getBestAction(V, hovered.r, hovered.c, gamma);
                    return (
                      <div key={av.name} style={{
                        padding: '3px 8px', borderRadius: 5, fontSize: 11, fontFamily: theme.font,
                        background: isBest ? 'rgba(139,92,246,0.2)' : 'transparent',
                        border: `1px solid ${isBest ? theme.colors.primary : theme.colors.border}`,
                        color: isBest ? theme.colors.text : theme.colors.textSecondary,
                      }}>
                        <span style={{ fontWeight: 600 }}>{av.name}:</span>{' '}
                        <span style={{ color: theme.colors.yellow }}>{av.reward.toFixed(2)}</span>
                        <span style={{ color: theme.colors.textMuted }}> + {gamma}*</span>
                        <span style={{ color: theme.colors.blue }}>{av.futureV.toFixed(2)}</span>
                        <span style={{ color: theme.colors.textMuted }}> = </span>
                        <span style={{ color: isBest ? theme.colors.green : theme.colors.textSecondary, fontWeight: isBest ? 700 : 400 }}>{av.value.toFixed(2)}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            ) : (
              <div style={{ fontSize: 11, color: theme.colors.textMuted, paddingTop: 4 }}>
                {iter === 0 ? 'Hover any cell to see the Bellman equation breakdown for each action.' : 'Hover a cell to see how V(s) = max [ R + gamma * V(next) ] is computed for each action.'}
              </div>
            )}
          </div>
        </div>

        {/* Gamma Slider + Iteration */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginTop: 10, padding: '0 4px' }}>
          <div style={{ flex: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
              <span style={{ fontSize: 11, color: theme.colors.textSecondary }}>Discount gamma</span>
              <span style={{ fontSize: 12, color: theme.colors.yellow, fontWeight: 600 }}>{gamma.toFixed(2)}</span>
            </div>
            <input type="range" min={0} max={0.99} step={0.01} value={gamma}
              onChange={e => handleGamma(parseFloat(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.yellow, cursor: 'pointer' }} />
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.colors.textMuted, marginTop: 1 }}>
              <span>0 (greedy)</span>
              <span>0.99 (far-sighted)</span>
            </div>
          </div>
          <div style={{ textAlign: 'center', minWidth: 70 }}>
            <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 2 }}>Iteration</div>
            <div style={{ fontSize: 22, fontWeight: 700, color: converged ? theme.colors.green : theme.colors.text }}>{iter}</div>
            {converged && <div style={{ fontSize: 9, color: theme.colors.green }}>converged</div>}
          </div>
        </div>

        {/* Insight */}
        <div style={{
          marginTop: 10, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.5,
          borderLeft: `3px solid ${converged ? theme.colors.green : iter === 0 ? theme.colors.primary : theme.colors.yellow}`,
          transition: 'border-color 0.3s',
        }}>
          <span style={{ color: converged ? theme.colors.green : iter === 0 ? theme.colors.primary : theme.colors.yellow, fontWeight: 600 }}>
            {converged ? 'Done: ' : iter === 0 ? 'Start: ' : 'Iter ' + iter + ': '}
          </span>
          {getInsight()}
        </div>
      </div>
    </div>
  );
}
